"""Auto-generated launch file for AutonomousGroundRobot.

Generated by ros2-sysmlv2 bridge pipeline from architecture model.

This launch file starts ONLY the custom generated nodes (not standard Nav2
servers). For a full Nav2 stack, launch Nav2's own bringup alongside this file.

Lifecycle management:
  - Custom nodes: managed by a lifecycle manager with bond_timeout=0.0
    (custom rclpy lifecycle nodes don't implement the Nav2 bond protocol)
  - Nav2 nodes: managed by Nav2's own lifecycle manager in its bringup
    (with bond_timeout=4.0, the Nav2 default)

Usage:
  # Custom nodes only (this file):
  ros2 launch autonomous_ground_robot autonomous_ground_robot.launch.py

  # With Nav2 (launch Nav2 bringup separately):
  ros2 launch nav2_bringup bringup_launch.py
  ros2 launch autonomous_ground_robot autonomous_ground_robot.launch.py
"""
import os

from ament_index_python.packages import get_package_share_directory
from launch import LaunchDescription
from launch.actions import DeclareLaunchArgument
from launch.substitutions import LaunchConfiguration
from launch_ros.actions import Node


def generate_launch_description():
    pkg_dir = get_package_share_directory('autonomous_ground_robot')

    params_file = LaunchConfiguration('params_file')
    declare_params_cmd = DeclareLaunchArgument(
        'params_file',
        default_value=os.path.join(pkg_dir, 'config', 'params.yaml'),
        description='Path to the parameter YAML file')

    ld = LaunchDescription()
    ld.add_action(declare_params_cmd)

    custom_lifecycle_nodes = []

    # ── Custom nodes (generated skeletons) ──

    lidar_driver_cmd = Node(
        package='autonomous_ground_robot',
        executable='lidar_driver',
        name='lidar',
        namespace='/sensors',
        output='screen',
        parameters=[params_file])
    ld.add_action(lidar_driver_cmd)
    custom_lifecycle_nodes.append('/sensors/lidar')

    imu_driver_cmd = Node(
        package='autonomous_ground_robot',
        executable='imu_driver',
        name='imu',
        namespace='/sensors',
        output='screen',
        parameters=[params_file])
    ld.add_action(imu_driver_cmd)
    custom_lifecycle_nodes.append('/sensors/imu')

    camera_driver_cmd = Node(
        package='autonomous_ground_robot',
        executable='camera_driver',
        name='camera',
        namespace='/sensors',
        output='screen',
        parameters=[params_file])
    ld.add_action(camera_driver_cmd)
    custom_lifecycle_nodes.append('/sensors/camera')

    obstacle_detector_cmd = Node(
        package='autonomous_ground_robot',
        executable='obstacle_detector',
        name='obstacle_detector',
        namespace='/perception',
        output='screen',
        parameters=[params_file])
    ld.add_action(obstacle_detector_cmd)
    custom_lifecycle_nodes.append('/perception/obstacle_detector')

    e_k_f_localizer_cmd = Node(
        package='autonomous_ground_robot',
        executable='e_k_f_localizer',
        name='ekf_localizer',
        namespace='/estimation',
        output='screen',
        parameters=[params_file])
    ld.add_action(e_k_f_localizer_cmd)
    custom_lifecycle_nodes.append('/estimation/ekf_localizer')

    path_planner_cmd = Node(
        package='autonomous_ground_robot',
        executable='path_planner',
        name='path_planner',
        namespace='/planning',
        output='screen',
        parameters=[params_file])
    ld.add_action(path_planner_cmd)
    custom_lifecycle_nodes.append('/planning/path_planner')

    trajectory_tracker_cmd = Node(
        package='autonomous_ground_robot',
        executable='trajectory_tracker',
        name='trajectory_tracker',
        namespace='/control',
        output='screen',
        parameters=[params_file])
    ld.add_action(trajectory_tracker_cmd)
    custom_lifecycle_nodes.append('/control/trajectory_tracker')

    a_g_r_velocity_smoother_cmd = Node(
        package='autonomous_ground_robot',
        executable='a_g_r_velocity_smoother',
        name='velocity_smoother',
        namespace='/safety',
        output='screen',
        parameters=[params_file])
    ld.add_action(a_g_r_velocity_smoother_cmd)
    custom_lifecycle_nodes.append('/safety/velocity_smoother')

    collision_guard_cmd = Node(
        package='autonomous_ground_robot',
        executable='collision_guard',
        name='collision_guard',
        namespace='/safety',
        output='screen',
        parameters=[params_file])
    ld.add_action(collision_guard_cmd)
    custom_lifecycle_nodes.append('/safety/collision_guard')

    static_map_server_cmd = Node(
        package='autonomous_ground_robot',
        executable='static_map_server',
        name='map_server',
        namespace='/',
        output='screen',
        parameters=[params_file])
    ld.add_action(static_map_server_cmd)
    custom_lifecycle_nodes.append('/map_server')

    mission_coordinator_cmd = Node(
        package='autonomous_ground_robot',
        executable='mission_coordinator',
        name='mission_coordinator',
        namespace='/',
        output='screen',
        parameters=[params_file])
    ld.add_action(mission_coordinator_cmd)
    custom_lifecycle_nodes.append('/mission_coordinator')

    # ── Lifecycle manager for custom nodes ──
    # Only included when lifecycle nodes exist. Uses nav2_lifecycle_manager
    # with bond_timeout=0.0 because rclpy LifecycleNode does not implement
    # the Nav2 bond protocol. Nav2's own nodes (if used) should be
    # managed by Nav2's own lifecycle manager with bonds enabled.
    # Alternative: use the generated activate_nodes.py script instead.

    if custom_lifecycle_nodes:
        lifecycle_manager_cmd = Node(
            package='nav2_lifecycle_manager',
            executable='lifecycle_manager',
            name='lifecycle_manager_custom',
            output='screen',
            parameters=[
                {'autostart': True},
                {'bond_timeout': 0.0},
                {'node_names': custom_lifecycle_nodes},
            ])
        ld.add_action(lifecycle_manager_cmd)

    # ── Conformance monitor (regular node, not lifecycle) ──

    conformance_monitor_cmd = Node(
        package='autonomous_ground_robot',
        executable='conformance_monitor',
        name='conformance_monitor',
        output='screen')
    ld.add_action(conformance_monitor_cmd)

    return ld
